Literal.Value:
'{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "autosize": {"type": "fit", "contains": "padding", "resize": true},
  "background": "transparent",
  "padding": {"top": 15, "left": 75, "right": 25, "bottom": 55},
  "config": {
    "font": "Segoe UI, system-ui, -apple-system, sans-serif",
    "axis": {
      "labelFontSize": 12,
      "titleFontSize": 14,
      "titleFontWeight": "normal",
      "titleColor": "#86868b",
      "labelColor": "#86868b",
      "gridColor": "#2a2a2d",
      "domainColor": "transparent",
      "tickColor": "transparent"
    }
  },
  "data": [
    {
      "name": "dataset",
      "transform": [
        {
          "type": "filter",
          "expr": "datum[''Close_Price''] != null && datum[''Close_Price''] > 0 && datum[''Volume''] != null && datum[''Volume''] > 0 && datum[''Volume''] < 2000000000"
        },
        {
          "type": "extent",
          "field": "Close_Price",
          "signal": "price_extent"
        },
        {
          "type": "bin",
          "field": "Close_Price",
          "extent": {"signal": "price_extent"},
          "maxbins": 60,
          "as": ["bin0", "bin1"]
        },
        {
          "type": "aggregate",
          "groupby": ["bin0", "bin1"],
          "ops": ["sum"],
          "fields": ["Volume"],
          "as": ["sum_Volume"]
        }
      ]
    },
    {
      "name": "current_price",
      "source": "dataset",
      "transform": [
        {
          "type": "filter",
          "expr": "datum[''Latest Price''] != null"
        },
        {
          "type": "aggregate",
          "ops": ["max"],
          "fields": ["Latest Price"],
          "as": ["current_price_val"]
        }
      ]
    }
  ],
  "scales": [
    {
      "name": "xscale",
      "type": "sqrt",
      "domain": {"data": "dataset", "field": "sum_Volume"},
      "range": "width",
      "nice": true,
      "zero": true
    },
    {
      "name": "yscale",
      "type": "linear",
      "domain": {"signal": "price_extent"},
      "range": "height",
      "nice": true,
      "zero": true
    },
    {
      "name": "colorscale",
      "type": "sqrt",
      "domain": {"data": "dataset", "field": "sum_Volume"},
      "range": ["#1a3a5c", "#2997ff"]
    }
  ],
  "axes": [
    {
      "orient": "bottom",
      "scale": "xscale",
      "title": "Historical Volume Traded (√ Scale)",
      "titlePadding": 15,
      "tickCount": 5,
      "format": "~s",
      "grid": true,
      "gridDash": [2, 4]
    },
    {
      "orient": "left",
      "scale": "yscale",
      "title": "Price Level (USD)",
      "titlePadding": 15,
      "tickCount": 8,
      "format": "$,.0f",
      "grid": false
    }
  ],
  "marks": [
    {
      "type": "rect",
      "from": {"data": "dataset"},
      "encode": {
        "enter": {
          "x": {"scale": "xscale", "value": 0},
          "x2": {"scale": "xscale", "field": "sum_Volume"},
          "y": {"scale": "yscale", "field": "bin1"},
          "y2": {"scale": "yscale", "field": "bin0", "offset": 1},
          "fill": {"scale": "colorscale", "field": "sum_Volume"},
          "cornerRadiusTopRight": {"value": 2},
          "cornerRadiusBottomRight": {"value": 2},
          "tooltip": {
            "signal": "{''Price Range'': ''$'' + format(datum.bin0, '',.2f'') + '' – $'' + format(datum.bin1, '',.2f''), ''Total Volume'': format(datum.sum_Volume, '',d''), ''Volume (M)'': format(datum.sum_Volume / 1e6, ''.1f'') + ''M''}"
          }
        },
        "update": {
          "fillOpacity": {"value": 0.9}
        },
        "hover": {
          "fillOpacity": {"value": 1.0},
          "fill": {"value": "#64d2ff"}
        }
      }
    },
    {
      "type": "rule",
      "from": {"data": "current_price"},
      "encode": {
        "enter": {
          "x": {"value": 0},
          "x2": {"signal": "width"},
          "y": {"scale": "yscale", "field": "current_price_val"},
          "stroke": {"value": "#ff9f0a"},
          "strokeWidth": {"value": 1.5},
          "strokeDash": {"value": [5, 3]},
          "opacity": {"value": 0.9}
        }
      }
    },
    {
      "type": "text",
      "from": {"data": "current_price"},
      "encode": {
        "enter": {
          "x": {"signal": "width"},
          "y": {"scale": "yscale", "field": "current_price_val", "offset": -5},
          "align": {"value": "right"},
          "text": {"signal": "''▶ $'' + format(datum.current_price_val, '',.2f'')"},
          "fill": {"value": "#ff9f0a"},
          "fontSize": {"value": 12},
          "fontWeight": {"value": "bold"}
        }
      }
    }
  ]
}'
